30	USING_YOSYS_NAMESPACE
31	PRIVATE_NAMESPACE_BEGIN
32	
33	// [[CITE]]
34	// Peter Eades; Xuemin Lin; W. F. Smyth, "A Fast Effective Heuristic For The Feedback Arc Set Problem"
35	// Information Processing Letters, Vol. 47, pp 319-323, 1993
36	// https://pdfs.semanticscholar.org/c7ed/d9acce96ca357876540e19664eb9d976637f.pdf
37	
38	// A topological sort (on a cell/wire graph) is always possible in a fully flattened RTLIL design without
39	// processes or logic loops where every wire has a single driver. Logic loops are illegal in RTLIL and wires
40	// with multiple drivers can be split by the `splitnets` pass; however, interdependencies between processes
41	// or module instances can create strongly connected components without introducing evaluation nondeterminism.
42	// We wish to support designs with such benign SCCs (as well as designs with multiple drivers per wire), so
43	// we sort the graph in a way that minimizes feedback arcs. If there are no feedback arcs in the sorted graph,
44	// then a more efficient evaluation method is possible, since eval() will always immediately converge.
45	template<class T>
46	struct Scheduler {
47		struct Vertex {
48			T *data;
49			Vertex *prev, *next;
50			pool<Vertex*> preds, succs;
51	
52			Vertex() : data(NULL), prev(this), next(this) {}
53			Vertex(T *data) : data(data), prev(NULL), next(NULL) {}
54	
55			bool empty() const
56			{
57				log_assert(data == NULL);
58				if (next == this) {
59					log_assert(prev == next);
60					return true;
61				}
62				return false;
63			}
64	
65			void link(Vertex *list)
66			{
67				log_assert(prev == NULL && next == NULL);
68				next = list;
69				prev = list->prev;
70				list->prev->next = this;
71				list->prev = this;
72			}
73	
74			void unlink()
75			{
76				log_assert(prev->next == this && next->prev == this);
77				prev->next = next;
78				next->prev = prev;
79				next = prev = NULL;
80			}
81	
82			int delta() const
83			{
84				return succs.size() - preds.size();
85			}
86		};
87	
88		std::vector<Vertex*> vertices;
89		Vertex *sources = new Vertex;
90		Vertex *sinks = new Vertex;
91		dict<int, Vertex*> bins;
92	
93		~Scheduler()
94		{
95			delete sources;
96			delete sinks;
97			for (auto bin : bins)
98				delete bin.second;
99			for (auto vertex : vertices)
100				delete vertex;
101		}
102	
103		Vertex *add(T *data)
104		{
105			Vertex *vertex = new Vertex(data);
106			vertices.push_back(vertex);
107			return vertex;
108		}
109	
110		void relink(Vertex *vertex)
111		{
112			if (vertex->succs.empty())
113				vertex->link(sinks);
114			else if (vertex->preds.empty())
115				vertex->link(sources);
116			else {
117				int delta = vertex->delta();
118				if (!bins.count(delta))
119					bins[delta] = new Vertex;
120				vertex->link(bins[delta]);
121			}
122		}
123	
124		Vertex *remove(Vertex *vertex)
125		{
126			vertex->unlink();
127			for (auto pred : vertex->preds) {
128				if (pred == vertex)
129					continue;
130				log_assert(pred->succs[vertex]);
131				pred->unlink();
132				pred->succs.erase(vertex);
133				relink(pred);
134			}
135			for (auto succ : vertex->succs) {
136				if (succ == vertex)
137					continue;
138				log_assert(succ->preds[vertex]);
139				succ->unlink();
140				succ->preds.erase(vertex);
141				relink(succ);
142			}
143			vertex->preds.clear();
144			vertex->succs.clear();
145			return vertex;
146		}
147	
148		std::vector<Vertex*> schedule()
149		{
150			std::vector<Vertex*> s1, s2r;
151			for (auto vertex : vertices)
152				relink(vertex);
153			bool bins_empty = false;
154			while (!(sinks->empty() && sources->empty() && bins_empty)) {
155				while (!sinks->empty())
156					s2r.push_back(remove(sinks->next));
157				while (!sources->empty())
158					s1.push_back(remove(sources->next));
159				// Choosing u in this implementation isn't O(1), but the paper handwaves which data structure they suggest
160				// using to get O(1) relinking *and* find-max-key ("it is clear"... no it isn't), so this code uses a very
161				// naive implementation of find-max-key.
162				bins_empty = true;
163				bins.template sort<std::greater<int>>();
164				for (auto bin : bins) {
165					if (!bin.second->empty()) {
166						bins_empty = false;
167						s1.push_back(remove(bin.second->next));
168						break;
169					}
170				}
171			}
172			s1.insert(s1.end(), s2r.rbegin(), s2r.rend());
173			return s1;
174		}
175	};
176	
177	bool is_unary_cell(RTLIL::IdString type)
178	{
179		return type.in(
180			ID($not), ID($logic_not), ID($reduce_and), ID($reduce_or), ID($reduce_xor), ID($reduce_xnor), ID($reduce_bool),
181			ID($pos), ID($neg));
182	}
183	
184	bool is_binary_cell(RTLIL::IdString type)
185	{
186		return type.in(
187			ID($and), ID($or), ID($xor), ID($xnor), ID($logic_and), ID($logic_or),
188			ID($shl), ID($sshl), ID($shr), ID($sshr), ID($shift), ID($shiftx),
189			ID($eq), ID($ne), ID($eqx), ID($nex), ID($gt), ID($ge), ID($lt), ID($le),
190			ID($add), ID($sub), ID($mul), ID($div), ID($mod), ID($modfloor), ID($divfloor));
191	}
192	
193	bool is_extending_cell(RTLIL::IdString type)
194	{
195		return !type.in(
196			ID($logic_not), ID($logic_and), ID($logic_or),
197			ID($reduce_and), ID($reduce_or), ID($reduce_xor), ID($reduce_xnor), ID($reduce_bool));
198	}
199	
200	bool is_inlinable_cell(RTLIL::IdString type)
201	{
202		return is_unary_cell(type) || is_binary_cell(type) || type.in(
203			ID($mux), ID($concat), ID($slice), ID($pmux), ID($bmux), ID($demux), ID($bwmux));
204	}
205	
206	bool is_ff_cell(RTLIL::IdString type)
207	{
208		return type.in(
209			ID($dff), ID($dffe), ID($sdff), ID($sdffe), ID($sdffce),
210			ID($adff), ID($adffe), ID($dffsr), ID($dffsre),
211			ID($aldff), ID($aldffe),
212			ID($dlatch), ID($adlatch), ID($dlatchsr), ID($sr));
213	}
214	
215	bool is_internal_cell(RTLIL::IdString type)
216	{
217		return !type.isPublic() && !type.begins_with("$paramod");
218	}
219	
220	bool is_effectful_cell(RTLIL::IdString type)
221	{
222		return type.in(ID($print), ID($check));
223	}
