240	enum class CxxrtlPortType {
241		UNKNOWN = 0, // or mixed comb/sync
242		COMB = 1,
243		SYNC = 2,
244	};
245	
246	CxxrtlPortType cxxrtl_port_type(RTLIL::Module *module, RTLIL::IdString port)
247	{
248		RTLIL::Wire *output_wire = module->wire(port);
249		log_assert(output_wire != nullptr);
250		bool is_comb = output_wire->get_bool_attribute(ID(cxxrtl_comb));
251		bool is_sync = output_wire->get_bool_attribute(ID(cxxrtl_sync));
252		if (is_comb && is_sync)
253			log_cmd_error("Port `%s.%s' is marked as both `cxxrtl_comb` and `cxxrtl_sync`.\n",
254			              module, log_signal(output_wire));
255		else if (is_comb)
256			return CxxrtlPortType::COMB;
257		else if (is_sync)
258			return CxxrtlPortType::SYNC;
259		return CxxrtlPortType::UNKNOWN;
260	}
261	
262	CxxrtlPortType cxxrtl_port_type(const RTLIL::Cell *cell, RTLIL::IdString port)
263	{
264		RTLIL::Module *cell_module = cell->module->design->module(cell->type);
265		if (cell_module == nullptr || !cell_module->get_bool_attribute(ID(cxxrtl_blackbox)))
266			return CxxrtlPortType::UNKNOWN;
267		return cxxrtl_port_type(cell_module, port);
268	}
269	
270	bool is_cxxrtl_comb_port(const RTLIL::Cell *cell, RTLIL::IdString port)
271	{
272		return cxxrtl_port_type(cell, port) == CxxrtlPortType::COMB;
273	}
274	
275	bool is_cxxrtl_sync_port(const RTLIL::Cell *cell, RTLIL::IdString port)
276	{
277		return cxxrtl_port_type(cell, port) == CxxrtlPortType::SYNC;
278	}
279	
280	struct FlowGraph {
281		struct Node {
282			enum class Type {
283				CONNECT,
284				CELL_SYNC,
285				CELL_EVAL,
286				EFFECT_SYNC,
287				PROCESS_SYNC,
288				PROCESS_CASE,
289				MEM_RDPORT,
290				MEM_WRPORTS,
291			};
292	
293			Type type;
294			RTLIL::SigSig connect = {};
295			const RTLIL::Cell *cell = nullptr;
296			std::vector<const RTLIL::Cell*> cells;
297			const RTLIL::Process *process = nullptr;
298			const Mem *mem = nullptr;
299			int portidx;
300		};
301	
302		std::vector<Node*> nodes;
303		dict<const RTLIL::Wire*, pool<Node*>> wire_comb_defs, wire_sync_defs, wire_uses;
304		dict<Node*, pool<const RTLIL::Wire*>> node_comb_defs, node_sync_defs, node_uses;
305		dict<const RTLIL::Wire*, bool> wire_def_inlinable;
306		dict<const RTLIL::Wire*, dict<Node*, bool>> wire_use_inlinable;
307		dict<RTLIL::SigBit, bool> bit_has_state;
308	
309		~FlowGraph()
310		{
311			for (auto node : nodes)
312				delete node;
313		}
314	
315		void add_defs(Node *node, const RTLIL::SigSpec &sig, bool is_ff, bool inlinable)
316		{
317			for (auto chunk : sig.chunks())
318				if (chunk.wire) {
319					if (is_ff) {
320						// A sync def means that a wire holds design state because it is driven directly by
321						// a flip-flop output. Such a wire can never be unbuffered.
322						wire_sync_defs[chunk.wire].insert(node);
323						node_sync_defs[node].insert(chunk.wire);
324					} else {
325						// A comb def means that a wire doesn't hold design state. It might still be connected,
326						// indirectly, to a flip-flop output.
327						wire_comb_defs[chunk.wire].insert(node);
328						node_comb_defs[node].insert(chunk.wire);
329					}
330				}
331			for (auto bit : sig)
332				bit_has_state[bit] |= is_ff;
333			// Only comb defs of an entire wire in the right order can be inlined.
334			if (!is_ff && sig.is_wire()) {
335				// Only a single def of a wire can be inlined. (Multiple defs of a wire are unsound, but we
336				// handle them anyway to avoid assertion failures later.)
337				if (!wire_def_inlinable.count(sig.as_wire()))
338					wire_def_inlinable[sig.as_wire()] = inlinable;
339				else
340					wire_def_inlinable[sig.as_wire()] = false;
341			}
342		}
343	
344		void add_uses(Node *node, const RTLIL::SigSpec &sig)
345		{
346			for (auto chunk : sig.chunks())
347				if (chunk.wire) {
348					wire_uses[chunk.wire].insert(node);
349					node_uses[node].insert(chunk.wire);
350					// Only a single use of an entire wire in the right order can be inlined. (But the use can include
351					// other chunks.) This is tracked per-node because a wire used by multiple nodes can still be inlined
352					// if all but one of those nodes is dead.
353					if (!wire_use_inlinable[chunk.wire].count(node))
354						wire_use_inlinable[chunk.wire][node] = true;
355					else
356						wire_use_inlinable[chunk.wire][node] = false;
357				}
358		}
359	
360		bool is_inlinable(const RTLIL::Wire *wire) const
361		{
362			// Can the wire be inlined at all?
363			if (wire_def_inlinable.count(wire))
364				return wire_def_inlinable.at(wire);
365			return false;
366		}
367	
368		bool is_inlinable(const RTLIL::Wire *wire, const pool<Node*> &nodes) const
369		{
370			// Can the wire be inlined, knowing that the given nodes are reachable?
371			if (nodes.size() != 1)
372				return false;
373			Node *node = *nodes.begin();
374			log_assert(node_uses.at(node).count(wire));
375			if (is_inlinable(wire) && wire_use_inlinable.count(wire) && wire_use_inlinable.at(wire).count(node))
376				return wire_use_inlinable.at(wire).at(node);
377			return false;
378		}
379	
380		// Connections
381		void add_connect_defs_uses(Node *node, const RTLIL::SigSig &conn)
382		{
383			add_defs(node, conn.first, /*is_ff=*/false, /*inlinable=*/true);
384			add_uses(node, conn.second);
385		}
386	
387		Node *add_node(const RTLIL::SigSig &conn)
388		{
389			Node *node = new Node;
390			node->type = Node::Type::CONNECT;
391			node->connect = conn;
392			nodes.push_back(node);
393			add_connect_defs_uses(node, conn);
394			return node;
395		}
396	
397		// Cells
398		void add_cell_sync_defs(Node *node, const RTLIL::Cell *cell)
399		{
400			// To understand why this node type is necessary and why it produces comb defs, consider a cell
401			// with input \i and sync output \o, used in a design such that \i is connected to \o. This does
402			// not result in a feedback arc because the output is synchronous. However, a naive implementation
403			// of code generation for cells that assigns to inputs, evaluates cells, assigns from outputs
404			// would not be able to immediately converge...
405			//
406			//   wire<1> i_tmp;
407			//   cell->p_i = i_tmp.curr;
408			//   cell->eval();
409			//   i_tmp.next = cell->p_o.curr;
410			//
411			// ... since the wire connecting the input and output ports would not be localizable. To solve
412			// this, the cell is split into two scheduling nodes; one exclusively for sync outputs, and
413			// another for inputs and all non-sync outputs. This way the generated code can be rearranged...
414			//
415			//   value<1> i_tmp;
416			//   i_tmp = cell->p_o.curr;
417			//   cell->p_i = i_tmp;
418			//   cell->eval();
419			//
420			// eliminating the unnecessary delta cycle. Conceptually, the CELL_SYNC node type is a series of
421			// connections of the form `connect \lhs \cell.\sync_output`; the right-hand side of these is not
422			// expressible as a wire in RTLIL. If it was expressible, then `\cell.\sync_output` would have
423			// a sync def, and this node would be an ordinary CONNECT node, with `\lhs` having a comb def.
424			// Because it isn't, a special node type is used, the right-hand side does not appear anywhere,
425			// and the left-hand side has a comb def.
426			for (auto conn : cell->connections())
427				if (cell->output(conn.first))
428					if (is_cxxrtl_sync_port(cell, conn.first)) {
429						// See note regarding inlinability below.
430						add_defs(node, conn.second, /*is_ff=*/false, /*inlinable=*/false);
431					}
432		}
433	
434		void add_cell_eval_defs_uses(Node *node, const RTLIL::Cell *cell)
435		{
436			for (auto conn : cell->connections()) {
437				if (cell->output(conn.first)) {
438					if (is_inlinable_cell(cell->type))
439						add_defs(node, conn.second, /*is_ff=*/false, /*inlinable=*/true);
440					else if (is_ff_cell(cell->type))
441						add_defs(node, conn.second, /*is_ff=*/true,  /*inlinable=*/false);
442					else if (is_internal_cell(cell->type))
443						add_defs(node, conn.second, /*is_ff=*/false, /*inlinable=*/false);
444					else if (!is_cxxrtl_sync_port(cell, conn.first)) {
445						// Although at first it looks like outputs of user-defined cells may always be inlined, the reality is
446						// more complex. Fully sync outputs produce no defs and so don't participate in inlining. Fully comb
447						// outputs are assigned in a different way depending on whether the cell's eval() immediately converged.
448						// Unknown/mixed outputs could be inlined, but should be rare in practical designs and don't justify
449						// the infrastructure required to inline outputs of cells with many of them.
450						add_defs(node, conn.second, /*is_ff=*/false, /*inlinable=*/false);
451					}
452				}
453				if (cell->input(conn.first))
454					add_uses(node, conn.second);
455			}
456		}
457	
458		Node *add_node(const RTLIL::Cell *cell)
459		{
460			log_assert(cell->known());
461	
462			bool has_fully_sync_outputs = false;
463			for (auto conn : cell->connections())
464				if (cell->output(conn.first) && is_cxxrtl_sync_port(cell, conn.first)) {
465					has_fully_sync_outputs = true;
466					break;
467				}
468			if (has_fully_sync_outputs) {
469				Node *node = new Node;
470				node->type = Node::Type::CELL_SYNC;
471				node->cell = cell;
472				nodes.push_back(node);
473				add_cell_sync_defs(node, cell);
474			}
475	
476			Node *node = new Node;
477			node->type = Node::Type::CELL_EVAL;
478			node->cell = cell;
479			nodes.push_back(node);
480			add_cell_eval_defs_uses(node, cell);
481			return node;
482		}
483	
484		Node *add_effect_sync_node(std::vector<const RTLIL::Cell*> cells)
485		{
486			Node *node = new Node;
487			node->type = Node::Type::EFFECT_SYNC;
488			node->cells = cells;
489			nodes.push_back(node);
490			return node;
491		}
492	
493		// Processes
494		void add_case_rule_defs_uses(Node *node, const RTLIL::CaseRule *case_)
495		{
496			for (auto &action : case_->actions) {
497				add_defs(node, action.first, /*is_ff=*/false, /*inlinable=*/false);
498				add_uses(node, action.second);
499			}
500			for (auto sub_switch : case_->switches) {
501				add_uses(node, sub_switch->signal);
502				for (auto sub_case : sub_switch->cases) {
503					for (auto &compare : sub_case->compare)
504						add_uses(node, compare);
505					add_case_rule_defs_uses(node, sub_case);
506				}
507			}
508		}
509	
510		void add_sync_rules_defs_uses(Node *node, const RTLIL::Process *process)
511		{
512			for (auto sync : process->syncs) {
513				for (auto &action : sync->actions) {
514					if (sync->type == RTLIL::STp || sync->type == RTLIL::STn || sync->type == RTLIL::STe)
515						add_defs(node, action.first, /*is_ff=*/true,  /*inlinable=*/false);
516					else
517						add_defs(node, action.first, /*is_ff=*/false, /*inlinable=*/false);
518					add_uses(node, action.second);
519				}
520				for (auto &memwr : sync->mem_write_actions) {
521					add_uses(node, memwr.address);
522					add_uses(node, memwr.data);
523					add_uses(node, memwr.enable);
524				}
525			}
526		}
527	
528		Node *add_node(const RTLIL::Process *process)
529		{
530			Node *node = new Node;
531			node->type = Node::Type::PROCESS_SYNC;
532			node->process = process;
533			nodes.push_back(node);
534			add_sync_rules_defs_uses(node, process);
535	
536			node = new Node;
537			node->type = Node::Type::PROCESS_CASE;
538			node->process = process;
539			nodes.push_back(node);
540			add_case_rule_defs_uses(node, &process->root_case);
541			return node;
542		}
543	
544		// Memories
545		void add_node(const Mem *mem) {
546			for (int i = 0; i < GetSize(mem->rd_ports); i++) {
547				auto &port = mem->rd_ports[i];
548				Node *node = new Node;
549				node->type = Node::Type::MEM_RDPORT;
550				node->mem = mem;
551				node->portidx = i;
552				nodes.push_back(node);
553				add_defs(node, port.data, /*is_ff=*/port.clk_enable, /*inlinable=*/false);
554				add_uses(node, port.clk);
555				add_uses(node, port.en);
556				add_uses(node, port.arst);
557				add_uses(node, port.srst);
558				add_uses(node, port.addr);
559				bool transparent = false;
560				for (int j = 0; j < GetSize(mem->wr_ports); j++) {
561					auto &wrport = mem->wr_ports[j];
562					if (port.transparency_mask[j]) {
563						// Our implementation of transparent read ports reads en, addr and data from every write port
564						// the read port is transparent with.
565						add_uses(node, wrport.en);
566						add_uses(node, wrport.addr);
567						add_uses(node, wrport.data);
568						transparent = true;
569					}
570				}
571				// Also we read the read address twice in this case (prevent inlining).
572				if (transparent)
573					add_uses(node, port.addr);
574			}
575			if (!mem->wr_ports.empty()) {
576				Node *node = new Node;
577				node->type = Node::Type::MEM_WRPORTS;
578				node->mem = mem;
579				nodes.push_back(node);
580				for (auto &port : mem->wr_ports) {
581					add_uses(node, port.clk);
582					add_uses(node, port.en);
583					add_uses(node, port.addr);
584					add_uses(node, port.data);
585				}
586			}
587		}
588	};
