590	std::vector<std::string> split_by(const std::string &str, const std::string &sep)
591	{
592		std::vector<std::string> result;
593		size_t prev = 0;
594		while (true) {
595			size_t curr = str.find_first_of(sep, prev);
596			if (curr == std::string::npos) {
597				std::string part = str.substr(prev);
598				if (!part.empty()) result.push_back(part);
599				break;
600			} else {
601				std::string part = str.substr(prev, curr - prev);
602				if (!part.empty()) result.push_back(part);
603				prev = curr + 1;
604			}
605		}
606		return result;
607	}
