609	std::string escape_c_string(const std::string &input)
610	{
611		std::string output;
612		output.push_back('"');
613		for (auto c : input) {
614			if (::isprint(c)) {
615				if (c == '\\' || c == '"')
616					output.push_back('\\');
617				output.push_back(c);
618			} else {
619				char l = c & 0x7, m = (c >> 3) & 0x7, h = (c >> 6) & 0x3;
620				output.append("\\");
621				output.push_back('0' + h);
622				output.push_back('0' + m);
623				output.push_back('0' + l);
624			}
625		}
626		output.push_back('"');
627		return output;
628	}
629	
630	std::string escape_cxx_string(const std::string &input)
631	{
632		std::string output = escape_c_string(input);
633		if (output.find('\0') != std::string::npos) {
634			output.insert(0, "std::string {");
635			output.append(stringf(", %zu}", input.size()));
636		}
637		return output;
638	}
