649	struct WireType {
650		enum Type {
651			// Non-referenced wire; is not a part of the design.
652			UNUSED,
653			// Double-buffered wire; is a class member, and holds design state.
654			BUFFERED,
655			// Single-buffered wire; is a class member, but holds no state.
656			MEMBER,
657			// Single-buffered wire; is a class member, and is computed on demand.
658			OUTLINE,
659			// Local wire; is a local variable in eval method.
660			LOCAL,
661			// Inline wire; is an unnamed temporary in eval method.
662			INLINE,
663			// Alias wire; is replaced with aliasee, except in debug info.
664			ALIAS,
665			// Const wire; is replaced with constant, except in debug info.
666			CONST,
667		};
668	
669		Type type = UNUSED;
670		const RTLIL::Cell *cell_subst = nullptr; // for INLINE
671		RTLIL::SigSpec sig_subst = {}; // for INLINE, ALIAS, and CONST
672	
673		WireType() = default;
674	
675		WireType(Type type) : type(type) {
676			log_assert(type == UNUSED || type == BUFFERED || type == MEMBER || type == OUTLINE || type == LOCAL);
677		}
678	
679		WireType(Type type, const RTLIL::Cell *cell) : type(type), cell_subst(cell) {
680			log_assert(type == INLINE && is_inlinable_cell(cell->type));
681		}
682	
683		WireType(Type type, RTLIL::SigSpec sig) : type(type), sig_subst(sig) {
684			log_assert(type == INLINE || (type == ALIAS && sig.is_wire()) || (type == CONST && sig.is_fully_const()));
685		}
686	
687		bool is_buffered() const { return type == BUFFERED; }
688		bool is_member() const { return type == BUFFERED || type == MEMBER || type == OUTLINE; }
689		bool is_outline() const { return type == OUTLINE; }
690		bool is_named() const { return is_member() || type == LOCAL; }
691		bool is_local() const { return type == LOCAL || type == INLINE; }
692		bool is_exact() const { return type == ALIAS || type == CONST; }
693	};
