750		// RTLIL allows any characters in names other than whitespace. This presents an issue for generating C++ code
751		// because C++ identifiers may be only alphanumeric, cannot clash with C++ keywords, and cannot clash with cxxrtl
752		// identifiers. This issue can be solved with a name mangling scheme. We choose a name mangling scheme that results
753		// in readable identifiers, does not depend on an up-to-date list of C++ keywords, and is easy to apply. Its rules:
754		//  1. All generated identifiers start with `_`.
755		//  1a. Generated identifiers for public names (beginning with `\`) start with `p_`.
756		//  1b. Generated identifiers for internal names (beginning with `$`) start with `i_`.
757		//  2. An underscore is escaped with another underscore, i.e. `__`.
758		//  3. Any other non-alnum character is escaped with underscores around its lowercase hex code, e.g. `@` as `_40_`.
759		std::string mangle_name(RTLIL::IdString name)
760		{
761			std::string mangled;
762			bool first = true;
763			for (char c : name.str()) {
764				if (first) {
765					first = false;
766					if (c == '\\')
767						mangled += "p_";
768					else if (c == '$')
769						mangled += "i_";
770					else
771						log_assert(false);
772				} else {
773					if (isalnum(c)) {
774						mangled += c;
775					} else if (c == '_') {
776						mangled += "__";
777					} else {
778						char l = c & 0xf, h = (c >> 4) & 0xf;
779						mangled += '_';
780						mangled += (h < 10 ? '0' + h : 'a' + h - 10);
781						mangled += (l < 10 ? '0' + l : 'a' + l - 10);
782						mangled += '_';
783					}
784				}
785			}
786			return mangled;
787		}
