848		std::vector<std::string> template_param_names(const RTLIL::Module *module)
849		{
850			if (!module->has_attribute(ID(cxxrtl_template)))
851				return {};
852	
853			if (!(module->attributes.at(ID(cxxrtl_template)).flags & RTLIL::CONST_FLAG_STRING))
854				log_cmd_error("Attribute `cxxrtl_template' of module `%s' is not a string.\n", module);
855	
856			std::vector<std::string> param_names = split_by(module->get_string_attribute(ID(cxxrtl_template)), " \t");
857			for (const auto &param_name : param_names) {
858				// Various lowercase prefixes (p_, i_, cell_, ...) are used for member variables, so require
859				// parameters to start with an uppercase letter to avoid name conflicts. (This is the convention
860				// in both Verilog and C++, anyway.)
861				if (!isupper(param_name[0]))
862					log_cmd_error("Attribute `cxxrtl_template' of module `%s' includes a parameter `%s', "
863					              "which does not start with an uppercase letter.\n",
864					              module, param_name.c_str());
865			}
866			return param_names;
867		}
