869		std::string template_params(const RTLIL::Module *module, bool is_decl)
870		{
871			std::vector<std::string> param_names = template_param_names(module);
872			if (param_names.empty())
873				return "";
874	
875			std::string params = "<";
876			bool first = true;
877			for (const auto &param_name : param_names) {
878				if (!first)
879					params += ", ";
880				first = false;
881				if (is_decl)
882					params += "size_t ";
883				params += param_name;
884			}
885			params += ">";
886			return params;
887		}
