889		std::string template_args(const RTLIL::Cell *cell)
890		{
891			RTLIL::Module *cell_module = cell->module->design->module(cell->type);
892			log_assert(cell_module != nullptr);
893			if (!cell_module->get_bool_attribute(ID(cxxrtl_blackbox)))
894				return "";
895	
896			std::vector<std::string> param_names = template_param_names(cell_module);
897			if (param_names.empty())
898				return "";
899	
900			std::string params = "<";
901			bool first = true;
902			for (const auto &param_name : param_names) {
903				if (!first)
904					params += ", ";
905				first = false;
906				params += "/*" + param_name + "=*/";
907				RTLIL::IdString id_param_name = '\\' + param_name;
908				if (!cell->hasParam(id_param_name))
909					log_cmd_error("Cell `%s.%s' does not have a parameter `%s', which is required by the templated module `%s'.\n",
910					              cell->module, cell, param_name.c_str(), cell_module);
911				RTLIL::Const param_value = cell->getParam(id_param_name);
912				if (((param_value.flags & ~RTLIL::CONST_FLAG_SIGNED) != 0) || param_value.as_int() < 0)
913					log_cmd_error("Parameter `%s' of cell `%s.%s', which is required by the templated module `%s', "
914					              "is not a positive integer.\n",
915					              param_name.c_str(), cell->module, cell, cell_module);
916				params += std::to_string(cell->getParam(id_param_name).as_int());
917			}
918			params += ">";
919			return params;
920		}
