940		void dump_const_init(const RTLIL::Const &data, int width, int offset = 0, bool fixed_width = false)
941		{
942			const int CHUNK_SIZE = 32;
943			f << "{";
944			while (width > 0) {
945				int chunk_width = min(width, CHUNK_SIZE);
946				uint32_t chunk = data.extract(offset, chunk_width).as_int();
947				if (fixed_width)
948					f << stringf("0x%.*xu", (3 + chunk_width) / 4, chunk);
949				else
950					f << stringf("%#xu", chunk);
951				if (width > CHUNK_SIZE)
952					f << ',';
953				offset += CHUNK_SIZE;
954				width  -= CHUNK_SIZE;
955			}
956			f << "}";
957		}
