970		bool dump_sigchunk(const RTLIL::SigChunk &chunk, bool is_lhs, bool for_debug = false)
971		{
972			if (chunk.wire == NULL) {
973				dump_const(chunk.data, chunk.width, chunk.offset);
974				return false;
975			} else {
976				const auto &wire_type = (for_debug ? debug_wire_types : wire_types)[chunk.wire];
977				switch (wire_type.type) {
978					case WireType::BUFFERED:
979						f << mangle(chunk.wire) << (is_lhs ? ".next" : ".curr");
980						break;
981					case WireType::MEMBER:
982					case WireType::LOCAL:
983					case WireType::OUTLINE:
984						f << mangle(chunk.wire);
985						break;
986					case WireType::INLINE:
987						log_assert(!is_lhs);
988						if (wire_type.cell_subst != nullptr) {
989							dump_cell_expr(wire_type.cell_subst, for_debug);
990							break;
991						}
992						YS_FALLTHROUGH
993					case WireType::ALIAS:
994					case WireType::CONST:
995						log_assert(!is_lhs);
996						return dump_sigspec(wire_type.sig_subst.extract(chunk.offset, chunk.width), is_lhs, for_debug);
997					case WireType::UNUSED:
998						log_assert(is_lhs);
999						f << "value<" << chunk.width << ">()";
1000						return false;
1001				}
1002				if (chunk.width == chunk.wire->width && chunk.offset == 0)
1003					return false;
1004				else if (chunk.width == 1)
1005					f << ".slice<" << chunk.offset << ">()";
1006				else
1007					f << ".slice<" << chunk.offset+chunk.width-1 << "," << chunk.offset << ">()";
1008				return true;
1009			}
1010		}
1011	
1012		bool dump_sigspec(const RTLIL::SigSpec &sig, bool is_lhs, bool for_debug = false)
1013		{
1014			if (sig.empty()) {
1015				f << "value<0>()";
1016				return false;
1017			} else if (sig.is_chunk()) {
1018				return dump_sigchunk(sig.as_chunk(), is_lhs, for_debug);
1019			} else {
1020				bool first = true;
1021				auto chunks = sig.chunks();
1022				for (auto it = chunks.rbegin(); it != chunks.rend(); it++) {
1023					if (!first)
1024						f << ".concat(";
1025					bool is_complex = dump_sigchunk(*it, is_lhs, for_debug);
1026					if (!is_lhs && it->width == 1) {
1027						size_t repeat = 1;
1028						while ((it + repeat) != chunks.rend() && *(it + repeat) == *it)
1029							repeat++;
1030						if (repeat > 1) {
1031							if (is_complex)
1032								f << ".val()";
1033							f << ".repeat<" << repeat << ">()";
1034						}
1035						it += repeat - 1;
1036					}
1037					if (!first)
1038						f << ")";
1039					first = false;
1040				}
1041				return true;
1042			}
1043		}
