1139				if (is_extending_cell(cell->type))
1140					f << '_' << (cell->getParam(ID::A_SIGNED).as_bool() ? 's' : 'u');
1141				f << "<" << cell->getParam(ID::Y_WIDTH).as_int() << ">(";
1142				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1143				f << ")";
1144			// Binary cells
1145			} else if (is_binary_cell(cell->type)) {
1146				f << cell->type.substr(1);
1147				if (is_extending_cell(cell->type))
1148					f << '_' << (cell->getParam(ID::A_SIGNED).as_bool() ? 's' : 'u') <<
1149					            (cell->getParam(ID::B_SIGNED).as_bool() ? 's' : 'u');
1150				f << "<" << cell->getParam(ID::Y_WIDTH).as_int() << ">(";
1151				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1152				f << ", ";
1153				dump_sigspec_rhs(cell->getPort(ID::B), for_debug);
1154				f << ")";
1155			// Muxes
1156			} else if (cell->type == ID($mux)) {
1157				f << "(";
1158				dump_sigspec_rhs(cell->getPort(ID::S), for_debug);
1159				f << " ? ";
1160				dump_sigspec_rhs(cell->getPort(ID::B), for_debug);
1161				f << " : ";
1162				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1163				f << ")";
1164			// Parallel (one-hot) muxes
1165			} else if (cell->type == ID($pmux)) {
1166				int width = cell->getParam(ID::WIDTH).as_int();
1167				int s_width = cell->getParam(ID::S_WIDTH).as_int();
1168				for (int part = 0; part < s_width; part++) {
1169					f << "(";
1170					dump_sigspec_rhs(cell->getPort(ID::S).extract(part), for_debug);
1171					f << " ? ";
1172					dump_sigspec_rhs(cell->getPort(ID::B).extract(part * width, width), for_debug);
1173					f << " : ";
1174				}
1175				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1176				for (int part = 0; part < s_width; part++) {
1177					f << ")";
1178				}
1179			// Big muxes
1180			} else if (cell->type == ID($bmux)) {
1181				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1182				f << ".bmux<";
1183				f << cell->getParam(ID::WIDTH).as_int();
1184				f << ">(";
1185				dump_sigspec_rhs(cell->getPort(ID::S), for_debug);
1186				f << ").val()";
1187			// Bitwise muxes
1188			} else if (cell->type == ID($bwmux)) {
1189				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1190				f << ".bwmux(";
1191				dump_sigspec_rhs(cell->getPort(ID::B), for_debug);
1192				f << ",";
1193				dump_sigspec_rhs(cell->getPort(ID::S), for_debug);
1194				f << ").val()";
1195			// Demuxes
1196			} else if (cell->type == ID($demux)) {
1197				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1198				f << ".demux<";
1199				f << GetSize(cell->getPort(ID::Y));
1200				f << ">(";
1201				dump_sigspec_rhs(cell->getPort(ID::S), for_debug);
1202				f << ").val()";
1203			// Concats
1204			} else if (cell->type == ID($concat)) {
1205				dump_sigspec_rhs(cell->getPort(ID::B), for_debug);
1206				f << ".concat(";
1207				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1208				f << ").val()";
1209			// Slices
1210			} else if (cell->type == ID($slice)) {
1211				dump_sigspec_rhs(cell->getPort(ID::A), for_debug);
1212				f << ".slice<";
1213				f << cell->getParam(ID::OFFSET).as_int() + cell->getParam(ID::Y_WIDTH).as_int() - 1;
1214				f << ",";
1215				f << cell->getParam(ID::OFFSET).as_int();
1216				f << ">().val()";
1217			} else {
1218				log_assert(false);
1219			}
1220		}
