1222		void dump_print(const RTLIL::Cell *cell)
1223		{
1224			Fmt fmt;
1225			fmt.parse_rtlil(cell);
1226	
1227			f << indent << "if (";
1228			dump_sigspec_rhs(cell->getPort(ID::EN));
1229			f << " == value<1>{1u}) {\n";
1230			inc_indent();
1231				dict<std::string, RTLIL::SigSpec> fmt_args;
1232				f << indent << "struct : public lazy_fmt {\n";
1233				inc_indent();
1234					f << indent << "std::string operator() () const override {\n";
1235					inc_indent();
1236						fmt.emit_cxxrtl(f, indent, [&](const RTLIL::SigSpec &sig) {
1237							if (sig.size() == 0)
1238								f << "value<0>()";
1239							else {
1240								std::string arg_name = "arg" + std::to_string(fmt_args.size());
1241								fmt_args[arg_name] = sig;
1242								f << arg_name;
1243							}
1244						}, "performer");
1245					dec_indent();
1246					f << indent << "}\n";
1247					f << indent << "struct performer *performer;\n";
1248					for (auto arg : fmt_args)
1249						f << indent << "value<" << arg.second.size() << "> " << arg.first << ";\n";
1250				dec_indent();
1251				f << indent << "} formatter;\n";
1252				f << indent << "formatter.performer = performer;\n";
1253				for (auto arg : fmt_args) {
1254					f << indent << "formatter." << arg.first << " = ";
1255					dump_sigspec_rhs(arg.second);
1256					f << ";\n";
1257				}
1258				f << indent << "if (performer) {\n";
1259				inc_indent();
1260					f << indent << "static const metadata_map attributes = ";
1261					dump_metadata_map(cell->attributes);
1262					f << ";\n";
1263					f << indent << "performer->on_print(formatter, attributes);\n";
1264				dec_indent();
1265				f << indent << "} else {\n";
1266				inc_indent();
1267					f << indent << print_output << " << formatter();\n";
1268				dec_indent();
1269				f << indent << "}\n";
1270			dec_indent();
1271			f << indent << "}\n";
1272		}
