1274		void dump_effect(const RTLIL::Cell *cell)
1275		{
1276			Fmt fmt;
1277			fmt.parse_rtlil(cell);
1278	
1279			f << indent << "if (";
1280			dump_sigspec_rhs(cell->getPort(ID::EN));
1281			f << ") {\n";
1282			inc_indent();
1283				dict<std::string, RTLIL::SigSpec> fmt_args;
1284				f << indent << "struct : public lazy_fmt {\n";
1285				inc_indent();
1286					f << indent << "std::string operator() () const override {\n";
1287					inc_indent();
1288						fmt.emit_cxxrtl(f, indent, [&](const RTLIL::SigSpec &sig) {
1289							if (sig.size() == 0)
1290								f << "value<0>()";
1291							else {
1292								std::string arg_name = "arg" + std::to_string(fmt_args.size());
1293								fmt_args[arg_name] = sig;
1294								f << arg_name;
1295							}
1296						}, "performer");
1297					dec_indent();
1298					f << indent << "}\n";
1299					f << indent << "struct performer *performer;\n";
1300					for (auto arg : fmt_args)
1301						f << indent << "value<" << arg.second.size() << "> " << arg.first << ";\n";
1302				dec_indent();
1303				f << indent << "} formatter;\n";
1304				f << indent << "formatter.performer = performer;\n";
1305				for (auto arg : fmt_args) {
1306					f << indent << "formatter." << arg.first << " = ";
1307					dump_sigspec_rhs(arg.second);
1308					f << ";\n";
1309				}
1310				if (cell->hasPort(ID::A)) {
1311					f << indent << "bool condition = (bool)";
1312					dump_sigspec_rhs(cell->getPort(ID::A));
1313					f << ";\n";
1314				}
1315				f << indent << "if (performer) {\n";
1316				inc_indent();
1317					f << indent << "static const metadata_map attributes = ";
1318					dump_metadata_map(cell->attributes);
1319					f << ";\n";
1320					if (cell->type == ID($print)) {
1321						f << indent << "performer->on_print(formatter, attributes);\n";
1322					} else if (cell->type == ID($check)) {
1323						std::string flavor = cell->getParam(ID::FLAVOR).decode_string();
1324						f << indent << "performer->on_check(";
1325						if (flavor == "assert")
1326							f << "flavor::ASSERT";
1327						else if (flavor == "assume")
1328							f << "flavor::ASSUME";
1329						else if (flavor == "live")
1330							f << "flavor::ASSERT_EVENTUALLY";
1331						else if (flavor == "fair")
1332							f << "flavor::ASSUME_EVENTUALLY";
1333						else if (flavor == "cover")
1334							f << "flavor::COVER";
1335						else log_assert(false);
1336						f << ", condition, formatter, attributes);\n";
1337					} else log_assert(false);
1338				dec_indent();
1339				f << indent << "} else {\n";
1340				inc_indent();
1341					if (cell->type == ID($print)) {
1342						f << indent << print_output << " << formatter();\n";
1343					} else if (cell->type == ID($check)) {
1344						std::string flavor = cell->getParam(ID::FLAVOR).decode_string();
1345						if (flavor == "assert" || flavor == "assume") {
1346							f << indent << "if (!condition) {\n";
1347							inc_indent();
1348								f << indent << "std::cerr << formatter();\n";
1349							dec_indent();
1350							f << indent << "}\n";
1351							f << indent << "CXXRTL_ASSERT(condition && \"Check failed\");\n";
1352						}
1353					} else log_assert(false);
1354				dec_indent();
1355				f << indent << "}\n";
1356			dec_indent();
1357			f << indent << "}\n";
1358		}
