1360		void dump_cell_eval(const RTLIL::Cell *cell, bool for_debug = false)
1361		{
1362			std::vector<const RTLIL::Cell*> inlined_cells;
1363			collect_cell_eval(cell, for_debug, inlined_cells);
1364			dump_inlined_cells(inlined_cells);
1365	
1366			// Elidable cells
1367			if (is_inlinable_cell(cell->type)) {
1368				f << indent;
1369				dump_sigspec_lhs(cell->getPort(ID::Y), for_debug);
1370				f << " = ";
1371				dump_cell_expr(cell, for_debug);
1372				f << ";\n";
1373			// Effectful cells
1374			} else if (is_effectful_cell(cell->type)) {
1375				log_assert(!for_debug);
1376	
1377				// Sync effectful cells are grouped into EFFECT_SYNC nodes in the FlowGraph.
1378				log_assert(!cell->getParam(ID::TRG_ENABLE).as_bool() || (cell->getParam(ID::TRG_ENABLE).as_bool() && cell->getParam(ID::TRG_WIDTH).as_int() == 0));
1379	
1380				if (!cell->getParam(ID::TRG_ENABLE).as_bool()) { // async effectful cell
1381					f << indent << "auto " << mangle(cell) << "_next = ";
1382					dump_sigspec_rhs(cell->getPort(ID::EN));
1383					f << ".concat(";
1384					if (cell->type == ID($print))
1385						dump_sigspec_rhs(cell->getPort(ID::ARGS));
1386					else if (cell->type == ID($check))
1387						dump_sigspec_rhs(cell->getPort(ID::A));
1388					else log_assert(false);
1389					f << ").val();\n";
1390	
1391					f << indent << "if (" << mangle(cell) << " != " << mangle(cell) << "_next) {\n";
1392					inc_indent();
1393						dump_effect(cell);
1394						f << indent << mangle(cell) << " = " << mangle(cell) << "_next;\n";
1395					dec_indent();
1396					f << indent << "}\n";
1397				} else { // initial effectful cell
1398					f << indent << "if (!" << mangle(cell) << ") {\n";
1399					inc_indent();
1400						dump_effect(cell);
1401						f << indent << mangle(cell) << " = value<1>{1u};\n";
1402					dec_indent();
1403					f << indent << "}\n";
1404				}
1405			// Flip-flops
1406			} else if (is_ff_cell(cell->type)) {
1407				log_assert(!for_debug);
1408				// Clocks might be slices of larger signals but should only ever be single bit
1409				if (cell->hasPort(ID::CLK) && is_valid_clock(cell->getPort(ID::CLK))) {
1410					// Edge-sensitive logic
1411					RTLIL::SigBit clk_bit = cell->getPort(ID::CLK)[0];
1412					clk_bit = sigmaps[clk_bit.wire->module](clk_bit);
1413					if (clk_bit.wire) {
1414						f << indent << "if (" << (cell->getParam(ID::CLK_POLARITY).as_bool() ? "posedge_" : "negedge_")
1415						            << mangle(clk_bit) << ") {\n";
1416					} else {
1417						f << indent << "if (false) {\n";
1418					}
1419					inc_indent();
1420						if (cell->hasPort(ID::EN)) {
1421							f << indent << "if (";
1422							dump_sigspec_rhs(cell->getPort(ID::EN));
1423							f << " == value<1> {" << cell->getParam(ID::EN_POLARITY).as_bool() << "u}) {\n";
1424							inc_indent();
1425						}
1426						f << indent;
1427						dump_sigspec_lhs(cell->getPort(ID::Q));
1428						f << " = ";
1429						dump_sigspec_rhs(cell->getPort(ID::D));
1430						f << ";\n";
1431						if (cell->hasPort(ID::EN) && cell->type != ID($sdffce)) {
1432							dec_indent();
1433							f << indent << "}\n";
1434						}
1435						if (cell->hasPort(ID::SRST)) {
1436							f << indent << "if (";
1437							dump_sigspec_rhs(cell->getPort(ID::SRST));
1438							f << " == value<1> {" << cell->getParam(ID::SRST_POLARITY).as_bool() << "u}) {\n";
1439							inc_indent();
1440								f << indent;
1441								dump_sigspec_lhs(cell->getPort(ID::Q));
1442								f << " = ";
1443								dump_const(cell->getParam(ID::SRST_VALUE));
1444								f << ";\n";
1445							dec_indent();
1446							f << indent << "}\n";
1447						}
1448						if (cell->hasPort(ID::EN) && cell->type == ID($sdffce)) {
1449							dec_indent();
1450							f << indent << "}\n";
1451						}
1452					dec_indent();
1453					f << indent << "}\n";
1454				} else if (cell->hasPort(ID::EN)) {
1455					// Level-sensitive logic
1456					f << indent << "if (";
1457					dump_sigspec_rhs(cell->getPort(ID::EN));
1458					f << " == value<1> {" << cell->getParam(ID::EN_POLARITY).as_bool() << "u}) {\n";
1459					inc_indent();
1460						f << indent;
1461						dump_sigspec_lhs(cell->getPort(ID::Q));
1462						f << " = ";
1463						dump_sigspec_rhs(cell->getPort(ID::D));
1464						f << ";\n";
1465					dec_indent();
1466					f << indent << "}\n";
1467				}
1468				if (cell->hasPort(ID::ARST)) {
1469					// Asynchronous reset (entire coarse cell at once)
1470					f << indent << "if (";
1471					dump_sigspec_rhs(cell->getPort(ID::ARST));
1472					f << " == value<1> {" << cell->getParam(ID::ARST_POLARITY).as_bool() << "u}) {\n";
1473					inc_indent();
1474						f << indent;
1475						dump_sigspec_lhs(cell->getPort(ID::Q));
1476						f << " = ";
1477						dump_const(cell->getParam(ID::ARST_VALUE));
1478						f << ";\n";
1479					dec_indent();
1480					f << indent << "}\n";
1481				}
1482				if (cell->hasPort(ID::ALOAD)) {
1483					// Asynchronous load
1484					f << indent << "if (";
1485					dump_sigspec_rhs(cell->getPort(ID::ALOAD));
1486					f << " == value<1> {" << cell->getParam(ID::ALOAD_POLARITY).as_bool() << "u}) {\n";
1487					inc_indent();
1488						f << indent;
1489						dump_sigspec_lhs(cell->getPort(ID::Q));
1490						f << " = ";
1491						dump_sigspec_rhs(cell->getPort(ID::AD));
1492						f << ";\n";
1493					dec_indent();
1494					f << indent << "}\n";
1495				}
1496				if (cell->hasPort(ID::SET)) {
1497					// Asynchronous set (for individual bits)
1498					f << indent;
1499					dump_sigspec_lhs(cell->getPort(ID::Q));
1500					f << " = ";
1501					dump_sigspec_rhs(cell->getPort(ID::Q));
1502					f << ".update(";
1503					dump_const(RTLIL::Const(RTLIL::S1, cell->getParam(ID::WIDTH).as_int()));
1504					f << ", ";
1505					dump_sigspec_rhs(cell->getPort(ID::SET));
1506					f << (cell->getParam(ID::SET_POLARITY).as_bool() ? "" : ".bit_not()") << ");\n";
1507				}
1508				if (cell->hasPort(ID::CLR)) {
1509					// Asynchronous clear (for individual bits; priority over set)
1510					f << indent;
1511					dump_sigspec_lhs(cell->getPort(ID::Q));
1512					f << " = ";
1513					dump_sigspec_rhs(cell->getPort(ID::Q));
1514					f << ".update(";
1515					dump_const(RTLIL::Const(RTLIL::S0, cell->getParam(ID::WIDTH).as_int()));
1516					f << ", ";
1517					dump_sigspec_rhs(cell->getPort(ID::CLR));
1518					f << (cell->getParam(ID::CLR_POLARITY).as_bool() ? "" : ".bit_not()") << ");\n";
1519				}
1520			// Internal cells
1521			} else if (is_internal_cell(cell->type)) {
1522				log_cmd_error("Unsupported internal cell `%s'.\n", cell->type);
1523			// User cells
1524			} else if (for_debug) {
1525				// Outlines are called on demand when computing the value of a debug item. Nothing to do here.
1526			} else {
1527				log_assert(cell->known());
1528				bool buffered_inputs = false;
1529				const char *access = is_cxxrtl_blackbox_cell(cell) ? "->" : ".";
1530				for (auto conn : cell->connections())
1531					if (cell->input(conn.first)) {
1532						RTLIL::Module *cell_module = cell->module->design->module(cell->type);
1533						log_assert(cell_module != nullptr && cell_module->wire(conn.first));
1534						RTLIL::Wire *cell_module_wire = cell_module->wire(conn.first);
1535						f << indent << mangle(cell) << access << mangle_wire_name(conn.first);
1536						if (!is_cxxrtl_blackbox_cell(cell) && wire_types[cell_module_wire].is_buffered()) {
1537							buffered_inputs = true;
1538							f << ".next";
1539						}
1540						f << " = ";
1541						dump_sigspec_rhs(conn.second);
1542						f << ";\n";
1543						if (getenv("CXXRTL_VOID_MY_WARRANTY") && conn.second.is_wire()) {
1544							// Until we have proper clock tree detection, this really awful hack that opportunistically
1545							// propagates prev_* values for clocks can be used to estimate how much faster a design could
1546							// be if only one clock edge was simulated by replacing:
1547							//   top.p_clk = value<1>{0u}; top.step();
1548							//   top.p_clk = value<1>{1u}; top.step();
1549							// with:
1550							//   top.prev_p_clk = value<1>{0u}; top.p_clk = value<1>{1u}; top.step();
1551							// Don't rely on this; it will be removed without warning.
1552							if (edge_wires[conn.second.as_wire()] && edge_wires[cell_module_wire]) {
1553								f << indent << mangle(cell) << access << "prev_" << mangle(cell_module_wire) << " = ";
1554								f << "prev_" << mangle(conn.second.as_wire()) << ";\n";
1555							}
1556						}
1557					}
1558				auto assign_from_outputs = [&](bool cell_converged) {
1559					for (auto conn : cell->connections()) {
1560						if (cell->output(conn.first)) {
1561							if (conn.second.empty())
1562								continue; // ignore disconnected ports
1563							if (is_cxxrtl_sync_port(cell, conn.first))
1564								continue; // fully sync ports are handled in CELL_SYNC nodes
1565							f << indent;
1566							dump_sigspec_lhs(conn.second);
1567							f << " = " << mangle(cell) << access << mangle_wire_name(conn.first);
1568							// Similarly to how there is no purpose to buffering cell inputs, there is also no purpose to buffering
1569							// combinatorial cell outputs in case the cell converges within one cycle. (To convince yourself that
1570							// this optimization is valid, consider that, since the cell converged within one cycle, it would not
1571							// have any buffered wires if they were not output ports. Imagine inlining the cell's eval() function,
1572							// and consider the fate of the localized wires that used to be output ports.)
1573							//
1574							// It is not possible to know apriori whether the cell (which may be late bound) will converge immediately.
1575							// Because of this, the choice between using .curr (appropriate for buffered outputs) and .next (appropriate
1576							// for unbuffered outputs) is made at runtime.
1577							if (cell_converged && is_cxxrtl_comb_port(cell, conn.first))
1578								f << ".next;\n";
1579							else
1580								f << ".curr;\n";
1581						}
1582					}
1583				};
1584				if (buffered_inputs) {
1585					// If we have any buffered inputs, there's no chance of converging immediately.
1586					f << indent << mangle(cell) << access << "eval(performer);\n";
1587					f << indent << "converged = false;\n";
1588					assign_from_outputs(/*cell_converged=*/false);
1589				} else {
1590					f << indent << "if (" << mangle(cell) << access << "eval(performer)) {\n";
1591					inc_indent();
1592						assign_from_outputs(/*cell_converged=*/true);
1593					dec_indent();
1594					f << indent << "} else {\n";
1595					inc_indent();
1596						f << indent << "converged = false;\n";
1597						assign_from_outputs(/*cell_converged=*/false);
1598					dec_indent();
1599					f << indent << "}\n";
1600				}
1601			}
1602		}
