1604		void collect_cell_eval(const RTLIL::Cell *cell, bool for_debug, std::vector<const RTLIL::Cell*> &cells)
1605		{
1606			cells.push_back(cell);
1607			for (auto port : cell->connections())
1608				if (cell->input(port.first))
1609					collect_sigspec_rhs(port.second, for_debug, cells);
