1612		void dump_assign(const RTLIL::SigSig &sigsig, bool for_debug = false)
1613		{
1614			f << indent;
1615			dump_sigspec_lhs(sigsig.first, for_debug);
1616			f << " = ";
1617			dump_sigspec_rhs(sigsig.second, for_debug);
1618			f << ";\n";
1619		}
