1621		void dump_case_rule(const RTLIL::CaseRule *rule, bool for_debug = false)
1622		{
1623			for (auto action : rule->actions)
1624				dump_assign(action, for_debug);
1625			for (auto switch_ : rule->switches)
1626				dump_switch_rule(switch_, for_debug);
1627		}
1628	
1629		void dump_switch_rule(const RTLIL::SwitchRule *rule, bool for_debug = false)
1630		{
1631			// The switch attributes are printed before the switch condition is captured.
1632			dump_attrs(rule);
1633			std::string signal_temp = fresh_temporary();
1634			f << indent << "const value<" << rule->signal.size() << "> &" << signal_temp << " = ";
1635			dump_sigspec(rule->signal, /*is_lhs=*/false, for_debug);
1636			f << ";\n";
1637	
1638			bool first = true;
1639			for (auto case_ : rule->cases) {
1640				// The case attributes (for nested cases) are printed before the if/else if/else statement.
1641				dump_attrs(rule);
1642				f << indent;
1643				if (!first)
1644					f << "} else ";
1645				first = false;
1646				if (!case_->compare.empty()) {
1647					f << "if (";
1648					bool first = true;
1649					for (auto &compare : case_->compare) {
1650						if (!first)
1651							f << " || ";
1652						first = false;
1653						if (compare.is_fully_def()) {
1654							f << signal_temp << " == ";
1655							dump_sigspec(compare, /*is_lhs=*/false, for_debug);
1656						} else if (compare.is_fully_const()) {
1657							RTLIL::Const::Builder compare_mask_builder(compare.size());
1658							RTLIL::Const::Builder compare_value_builder(compare.size());
1659							for (auto bit : compare.as_const()) {
1660								switch (bit) {
1661									case RTLIL::S0:
1662									case RTLIL::S1:
1663										compare_mask_builder.push_back(RTLIL::S1);
1664										compare_value_builder.push_back(bit);
1665										break;
1666	
1667									case RTLIL::Sx:
1668									case RTLIL::Sz:
1669									case RTLIL::Sa:
1670										compare_mask_builder.push_back(RTLIL::S0);
1671										compare_value_builder.push_back(RTLIL::S0);
1672										break;
1673	
1674									default:
1675										log_assert(false);
1676								}
1677							}
1678							RTLIL::Const compare_mask = compare_mask_builder.build();
1679							RTLIL::Const compare_value = compare_value_builder.build();
1680							f << "and_uu<" << compare.size() << ">(" << signal_temp << ", ";
1681							dump_const(compare_mask);
1682							f << ") == ";
1683							dump_const(compare_value);
1684						} else {
1685							log_assert(false);
1686						}
1687					}
1688					f << ") ";
1689				}
1690				f << "{\n";
1691				inc_indent();
1692					dump_case_rule(case_, for_debug);
1693				dec_indent();
1694			}
1695			f << indent << "}\n";
1696		}
