1707		void dump_process_syncs(const RTLIL::Process *proc, bool for_debug = false)
1708		{
1709			dump_attrs(proc);
1710			f << indent << "// process " << proc->name.str() << " syncs\n";
1711			for (auto sync : proc->syncs) {
1712				log_assert(!for_debug || sync->type == RTLIL::STa);
1713	
1714				RTLIL::SigBit sync_bit;
1715				if (!sync->signal.empty()) {
1716					sync_bit = sync->signal[0];
1717					sync_bit = sigmaps[sync_bit.wire->module](sync_bit);
1718					if (!sync_bit.is_wire())
1719						continue; // a clock, or more commonly a reset, can be tied to a constant driver
1720				}
1721	
1722				pool<std::string> events;
1723				switch (sync->type) {
1724					case RTLIL::STp:
1725						log_assert(sync_bit.wire != nullptr);
1726						events.insert("posedge_" + mangle(sync_bit));
1727						break;
1728					case RTLIL::STn:
1729						log_assert(sync_bit.wire != nullptr);
1730						events.insert("negedge_" + mangle(sync_bit));
1731						break;
1732					case RTLIL::STe:
1733						log_assert(sync_bit.wire != nullptr);
1734						events.insert("posedge_" + mangle(sync_bit));
1735						events.insert("negedge_" + mangle(sync_bit));
1736						break;
1737	
1738					case RTLIL::STa:
1739						events.insert("true");
1740						break;
1741	
1742					case RTLIL::ST0:
1743					case RTLIL::ST1:
1744					case RTLIL::STg:
1745					case RTLIL::STi:
1746						log_assert(false);
1747				}
1748				if (!events.empty()) {
1749					f << indent << "if (";
1750					bool first = true;
1751					for (auto &event : events) {
1752						if (!first)
1753							f << " || ";
1754						first = false;
1755						f << event;
1756					}
1757					f << ") {\n";
1758					inc_indent();
1759						for (auto &action : sync->actions)
1760							dump_assign(action, for_debug);
1761						for (auto &memwr : sync->mem_write_actions) {
1762							RTLIL::Memory *memory = proc->module->memories.at(memwr.memid);
1763							std::string valid_index_temp = fresh_temporary();
1764							f << indent << "auto " << valid_index_temp << " = memory_index(";
1765							dump_sigspec_rhs(memwr.address);
1766							f << ", " << memory->start_offset << ", " << memory->size << ");\n";
1767							// See below for rationale of having both the assert and the condition.
1768							//
1769							// If assertions are disabled, out of bounds writes are defined to do nothing.
1770							f << indent << "CXXRTL_ASSERT(" << valid_index_temp << ".valid && \"out of bounds write\");\n";
1771							f << indent << "if (" << valid_index_temp << ".valid) {\n";
1772							inc_indent();
1773								f << indent << mangle(memory) << ".update(" << valid_index_temp << ".index, ";
1774								dump_sigspec_rhs(memwr.data);
1775								f << ", ";
1776								dump_sigspec_rhs(memwr.enable);
1777								f << ");\n";
1778							dec_indent();
1779							f << indent << "}\n";
1780						}
1781					dec_indent();
1782					f << indent << "}\n";
1783				}
1784			}
1785		}
1786	
1787		void dump_cell_effect_sync(std::vector<const RTLIL::Cell*> &cells)
1788		{
1789			log_assert(!cells.empty());
1790			const auto &trg = cells[0]->getPort(ID::TRG);
1791			const auto &trg_polarity = cells[0]->getParam(ID::TRG_POLARITY);
1792	
1793			f << indent << "if (";
1794			for (int i = 0; i < trg.size(); i++) {
1795				RTLIL::SigBit trg_bit = trg[i];
1796				trg_bit = sigmaps[trg_bit.wire->module](trg_bit);
1797				log_assert(trg_bit.wire);
1798	
1799				if (i != 0)
1800					f << " || ";
1801	
1802				if (trg_polarity[i] == State::S1)
1803					f << "posedge_";
1804				else
1805					f << "negedge_";
1806				f << mangle(trg_bit);
1807			}
1808			f << ") {\n";
1809			inc_indent();
1810				std::sort(cells.begin(), cells.end(), [](const RTLIL::Cell *a, const RTLIL::Cell *b) {
1811					return a->getParam(ID::PRIORITY).as_int() > b->getParam(ID::PRIORITY).as_int();
1812				});
1813				for (auto cell : cells) {
1814					log_assert(cell->getParam(ID::TRG_ENABLE).as_bool());
1815					log_assert(cell->getPort(ID::TRG) == trg);
1816					log_assert(cell->getParam(ID::TRG_POLARITY) == trg_polarity);
1817	
1818					std::vector<const RTLIL::Cell*> inlined_cells;
1819					collect_cell_eval(cell, /*for_debug=*/false, inlined_cells);
1820					dump_inlined_cells(inlined_cells);
1821					dump_effect(cell);
1822				}
1823			dec_indent();
1824	
1825			f << indent << "}\n";
1826		}
1827	
1828		void dump_mem_rdport(const Mem *mem, int portidx, bool for_debug = false)
1829		{
1830			auto &port = mem->rd_ports[portidx];
1831			dump_attrs(&port);
1832			f << indent << "// memory " << mem->memid.str() << " read port " << portidx << "\n";
1833			if (port.clk_enable) {
1834				log_assert(!for_debug);
1835				RTLIL::SigBit clk_bit = port.clk[0];
1836				clk_bit = sigmaps[clk_bit.wire->module](clk_bit);
1837				if (clk_bit.wire) {
1838					f << indent << "if (" << (port.clk_polarity ? "posedge_" : "negedge_")
1839						    << mangle(clk_bit) << ") {\n";
1840				} else {
1841					f << indent << "if (false) {\n";
1842				}
1843				inc_indent();
1844			}
1845			std::vector<const RTLIL::Cell*> inlined_cells_addr;
1846			collect_sigspec_rhs(port.addr, for_debug, inlined_cells_addr);
1847			if (!inlined_cells_addr.empty())
1848				dump_inlined_cells(inlined_cells_addr);
1849			std::string valid_index_temp = fresh_temporary();
1850			f << indent << "auto " << valid_index_temp << " = memory_index(";
1851			// Almost all non-elidable cells cannot appear in debug_eval(), but $memrd is an exception; asynchronous
1852			// memory read ports can.
1853			dump_sigspec_rhs(port.addr, for_debug);
1854			f << ", " << mem->start_offset << ", " << mem->size << ");\n";
1855			bool has_enable = port.clk_enable && !port.en.is_fully_ones();
1856			if (has_enable) {
1857				std::vector<const RTLIL::Cell*> inlined_cells_en;
1858				collect_sigspec_rhs(port.en, for_debug, inlined_cells_en);
1859				if (!inlined_cells_en.empty())
1860					dump_inlined_cells(inlined_cells_en);
1861				f << indent << "if (";
1862				dump_sigspec_rhs(port.en);
1863				f << ") {\n";
1864				inc_indent();
1865			}
1866			// The generated code has two bounds checks; one in an assertion, and another that guards the read.
1867			// This is done so that the code does not invoke undefined behavior under any conditions, but nevertheless
1868			// loudly crashes if an illegal condition is encountered. The assert may be turned off with -DCXXRTL_NDEBUG
1869			// not only for release builds, but also to make sure the simulator (which is presumably embedded in some
1870			// larger program) will never crash the code that calls into it.
1871			//
1872			// If assertions are disabled, out of bounds reads are defined to return zero.
1873			f << indent << "CXXRTL_ASSERT(" << valid_index_temp << ".valid && \"out of bounds read\");\n";
1874			f << indent << "if(" << valid_index_temp << ".valid) {\n";
1875			inc_indent();
1876				if (!mem->wr_ports.empty()) {
1877					std::string lhs_temp = fresh_temporary();
1878					f << indent << "value<" << mem->width << "> " << lhs_temp << " = "
1879						    << mangle(mem) << "[" << valid_index_temp << ".index];\n";
1880					bool transparent = false;
1881					for (auto bit : port.transparency_mask)
1882						if (bit)
1883							transparent = true;
1884					if (transparent) {
1885						std::string addr_temp = fresh_temporary();
1886						f << indent << "const value<" << port.addr.size() << "> &" << addr_temp << " = ";
1887						dump_sigspec_rhs(port.addr);
1888						f << ";\n";
1889						for (int i = 0; i < GetSize(mem->wr_ports); i++) {
1890							auto &wrport = mem->wr_ports[i];
1891							if (!port.transparency_mask[i])
1892								continue;
1893							f << indent << "if (" << addr_temp << " == ";
1894							dump_sigspec_rhs(wrport.addr);
1895							f << ") {\n";
1896							inc_indent();
1897								f << indent << lhs_temp << " = " << lhs_temp;
1898								f << ".update(";
1899								dump_sigspec_rhs(wrport.data);
1900								f << ", ";
1901								dump_sigspec_rhs(wrport.en);
1902								f << ");\n";
1903							dec_indent();
1904							f << indent << "}\n";
1905						}
1906					}
1907					f << indent;
1908					dump_sigspec_lhs(port.data);
1909					f << " = " << lhs_temp << ";\n";
1910				} else {
1911					f << indent;
1912					dump_sigspec_lhs(port.data);
1913					f << " = " << mangle(mem) << "[" << valid_index_temp << ".index];\n";
1914				}
1915			dec_indent();
1916			f << indent << "} else {\n";
1917			inc_indent();
1918				f << indent;
1919				dump_sigspec_lhs(port.data);
1920				f << " = value<" << mem->width << "> {};\n";
1921			dec_indent();
1922			f << indent << "}\n";
1923			if (has_enable && !port.ce_over_srst) {
1924				dec_indent();
1925				f << indent << "}\n";
1926			}
1927			if (port.srst != State::S0) {
1928				// Synchronous reset
1929				std::vector<const RTLIL::Cell*> inlined_cells_srst;
1930				collect_sigspec_rhs(port.srst, for_debug, inlined_cells_srst);
1931				if (!inlined_cells_srst.empty())
1932					dump_inlined_cells(inlined_cells_srst);
1933				f << indent << "if (";
1934				dump_sigspec_rhs(port.srst);
1935				f << " == value<1> {1u}) {\n";
1936				inc_indent();
1937					f << indent;
1938					dump_sigspec_lhs(port.data);
1939					f << " = ";
1940					dump_const(port.srst_value);
1941					f << ";\n";
1942				dec_indent();
1943				f << indent << "}\n";
1944			}
1945			if (has_enable && port.ce_over_srst) {
1946				dec_indent();
1947				f << indent << "}\n";
1948			}
1949			if (port.clk_enable) {
1950				dec_indent();
1951				f << indent << "}\n";
1952			}
1953			if (port.arst != State::S0) {
1954				// Asynchronous reset
1955				std::vector<const RTLIL::Cell*> inlined_cells_arst;
1956				collect_sigspec_rhs(port.arst, for_debug, inlined_cells_arst);
1957				if (!inlined_cells_arst.empty())
1958					dump_inlined_cells(inlined_cells_arst);
1959				f << indent << "if (";
1960				dump_sigspec_rhs(port.arst);
1961				f << " == value<1> {1u}) {\n";
1962				inc_indent();
1963					f << indent;
1964					dump_sigspec_lhs(port.data);
1965					f << " = ";
1966					dump_const(port.arst_value);
1967					f << ";\n";
1968				dec_indent();
1969				f << indent << "}\n";
1970			}
1971		}
1972	
1973		void dump_mem_wrports(const Mem *mem, bool for_debug = false)
1974		{
1975			log_assert(!for_debug);
1976			for (int portidx = 0; portidx < GetSize(mem->wr_ports); portidx++) {
1977				auto &port = mem->wr_ports[portidx];
1978				dump_attrs(&port);
1979				f << indent << "// memory " << mem->memid.str() << " write port " << portidx << "\n";
1980				if (port.clk_enable) {
1981					RTLIL::SigBit clk_bit = port.clk[0];
1982					clk_bit = sigmaps[clk_bit.wire->module](clk_bit);
1983					if (clk_bit.wire) {
1984						f << indent << "if (" << (port.clk_polarity ? "posedge_" : "negedge_")
1985						            << mangle(clk_bit) << ") {\n";
1986					} else {
1987						f << indent << "if (false) {\n";
1988					}
1989					inc_indent();
1990				}
1991				std::vector<const RTLIL::Cell*> inlined_cells_addr;
1992				collect_sigspec_rhs(port.addr, for_debug, inlined_cells_addr);
1993				if (!inlined_cells_addr.empty())
1994					dump_inlined_cells(inlined_cells_addr);
1995				std::string valid_index_temp = fresh_temporary();
1996				f << indent << "auto " << valid_index_temp << " = memory_index(";
1997				dump_sigspec_rhs(port.addr);
1998				f << ", " << mem->start_offset << ", " << mem->size << ");\n";
1999				// See above for rationale of having both the assert and the condition.
2000				//
2001				// If assertions are disabled, out of bounds writes are defined to do nothing.
2002				f << indent << "CXXRTL_ASSERT(" << valid_index_temp << ".valid && \"out of bounds write\");\n";
2003				f << indent << "if (" << valid_index_temp << ".valid) {\n";
2004				inc_indent();
2005					std::vector<const RTLIL::Cell*> inlined_cells;
2006					collect_sigspec_rhs(port.data, for_debug, inlined_cells);
2007					collect_sigspec_rhs(port.en, for_debug, inlined_cells);
2008					if (!inlined_cells.empty())
2009						dump_inlined_cells(inlined_cells);
2010					f << indent << mangle(mem) << ".update(" << valid_index_temp << ".index, ";
2011					dump_sigspec_rhs(port.data);
2012					f << ", ";
2013					dump_sigspec_rhs(port.en);
2014					f << ", " << portidx << ");\n";
2015				dec_indent();
2016				f << indent << "}\n";
2017				if (port.clk_enable) {
2018					dec_indent();
2019					f << indent << "}\n";
2020				}
2021			}
2022		}
