2024		void dump_wire(const RTLIL::Wire *wire, bool is_local)
2025		{
2026			const auto &wire_type = wire_types[wire];
2027			if (!wire_type.is_named() || wire_type.is_local() != is_local)
2028				return;
2029	
2030			dump_attrs(wire);
2031			f << indent;
2032			if (wire->port_input && wire->port_output)
2033				f << "/*inout*/ ";
2034			else if (wire->port_input)
2035				f << "/*input*/ ";
2036			else if (wire->port_output)
2037				f << "/*output*/ ";
2038			f << (wire_type.is_buffered() ? "wire" : "value");
2039			if (wire->module->has_attribute(ID(cxxrtl_blackbox)) && wire->has_attribute(ID(cxxrtl_width))) {
2040				f << "<" << wire->get_string_attribute(ID(cxxrtl_width)) << ">";
2041			} else {
2042				f << "<" << wire->width << ">";
2043			}
2044			f << " " << mangle(wire) << ";\n";
2045			if (edge_wires[wire]) {
2046				if (!wire_type.is_buffered()) {
2047					f << indent << "value<" << wire->width << "> prev_" << mangle(wire) << ";\n";
2048				}
2049				for (auto edge_type : edge_types) {
2050					if (edge_type.first.wire == wire) {
2051						std::string prev, next;
2052						if (!wire_type.is_buffered()) {
2053							prev = "prev_" + mangle(edge_type.first.wire);
2054							next =           mangle(edge_type.first.wire);
2055						} else {
2056							prev = mangle(edge_type.first.wire) + ".curr";
2057							next = mangle(edge_type.first.wire) + ".next";
2058						}
2059						prev += ".slice<" + std::to_string(edge_type.first.offset) + ">().val()";
2060						next += ".slice<" + std::to_string(edge_type.first.offset) + ">().val()";
2061						if (edge_type.second != RTLIL::STn) {
2062							f << indent << "bool posedge_" << mangle(edge_type.first) << "() const {\n";
2063							inc_indent();
2064								f << indent << "return !" << prev << " && " << next << ";\n";
2065							dec_indent();
2066							f << indent << "}\n";
2067						}
2068						if (edge_type.second != RTLIL::STp) {
2069							f << indent << "bool negedge_" << mangle(edge_type.first) << "() const {\n";
2070							inc_indent();
2071								f << indent << "return " << prev << " && !" << next << ";\n";
2072							dec_indent();
2073							f << indent << "}\n";
2074						}
2075					}
2076				}
2077			}
2078		}
