3470	struct CxxrtlBackend : public Backend {
3471		static constexpr int DEFAULT_OPT_LEVEL = 6;
3472		static constexpr int DEFAULT_DEBUG_LEVEL = 4;
3473	
3474		CxxrtlBackend() : Backend("cxxrtl", "convert design to C++ RTL simulation") { }
3475		void help() override
3476		{
3477			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
3478			log("\n");
3479			log("    write_cxxrtl [options] [filename]\n");
3480			log("\n");
3481			log("Write C++ code that simulates the design. The generated code requires a driver\n");
3482			log("that instantiates the design, toggles its clock, and interacts with its ports.\n");
3483			log("\n");
3484			log("The following driver may be used as an example for a design with a single clock\n");
3485			log("driving rising edge triggered flip-flops:\n");
3486			log("\n");
3487			log("    #include \"top.cc\"\n");
3488			log("\n");
3489			log("    int main() {\n");
3490			log("      cxxrtl_design::p_top top;\n");
3491			log("      top.step();\n");
3492			log("      while (1) {\n");
3493			log("        /* user logic */\n");
3494			log("        top.p_clk.set(false);\n");
3495			log("        top.step();\n");
3496			log("        top.p_clk.set(true);\n");
3497			log("        top.step();\n");
3498			log("      }\n");
3499			log("    }\n");
3500			log("\n");
3501			log("Note that CXXRTL simulations, just like the hardware they are simulating, are\n");
3502			log("subject to race conditions. If, in the example above, the user logic would run\n");
3503			log("simultaneously with the rising edge of the clock, the design would malfunction.\n");
3504			log("\n");
3505			log("This backend supports replacing parts of the design with black boxes implemented\n");
3506			log("in C++. If a module marked as a CXXRTL black box, its implementation is ignored,\n");
3507			log("and the generated code consists only of an interface and a factory function.\n");
3508			log("The driver must implement the factory function that creates an implementation of\n");
3509			log("the black box, taking into account the parameters it is instantiated with.\n");
3510			log("\n");
3511			log("For example, the following Verilog code defines a CXXRTL black box interface for\n");
3512			log("a synchronous debug sink:\n");
3513			log("\n");
3514			log("    (* cxxrtl_blackbox *)\n");
3515			log("    module debug(...);\n");
3516			log("      (* cxxrtl_edge = \"p\" *) input clk;\n");
3517			log("      input en;\n");
3518			log("      input [7:0] i_data;\n");
3519			log("      (* cxxrtl_sync *) output [7:0] o_data;\n");
3520			log("    endmodule\n");
3521			log("\n");
3522			log("For this HDL interface, this backend will generate the following C++ interface:\n");
3523			log("\n");
3524			log("    struct bb_p_debug : public module {\n");
3525			log("      value<1> p_clk;\n");
3526			log("      bool posedge_p_clk() const { /* ... */ }\n");
3527			log("      value<1> p_en;\n");
3528			log("      value<8> p_i_data;\n");
3529			log("      wire<8> p_o_data;\n");
3530			log("\n");
3531			log("      bool eval(performer *performer) override;\n");
3532			log("      virtual bool commit(observer &observer);\n");
3533			log("      bool commit() override;\n");
3534			log("\n");
3535			log("      static std::unique_ptr<bb_p_debug>\n");
3536			log("      create(std::string name, metadata_map parameters, metadata_map attributes);\n");
3537			log("    };\n");
3538			log("\n");
3539			log("The `create' function must be implemented by the driver. For example, it could\n");
3540			log("always provide an implementation logging the values to standard error stream:\n");
3541			log("\n");
3542			log("    namespace cxxrtl_design {\n");
3543			log("\n");
3544			log("    struct stderr_debug : public bb_p_debug {\n");
3545			log("      bool eval(performer *performer) override {\n");
3546			log("        if (posedge_p_clk() && p_en)\n");
3547			log("          fprintf(stderr, \"debug: %%02x\\n\", p_i_data.data[0]);\n");
3548			log("        p_o_data.next = p_i_data;\n");
3549			log("        return bb_p_debug::eval(performer);\n");
3550			log("      }\n");
3551			log("    };\n");
3552			log("\n");
3553			log("    std::unique_ptr<bb_p_debug>\n");
3554			log("    bb_p_debug::create(std::string name, cxxrtl::metadata_map parameters,\n");
3555			log("                       cxxrtl::metadata_map attributes) {\n");
3556			log("      return std::make_unique<stderr_debug>();\n");
3557			log("    }\n");
3558			log("\n");
3559			log("    }\n");
3560			log("\n");
3561			log("For complex applications of black boxes, it is possible to parameterize their\n");
3562			log("port widths. For example, the following Verilog code defines a CXXRTL black box\n");
3563			log("interface for a configurable width debug sink:\n");
3564			log("\n");
3565			log("    (* cxxrtl_blackbox, cxxrtl_template = \"WIDTH\" *)\n");
3566			log("    module debug(...);\n");
3567			log("      parameter WIDTH = 8;\n");
3568			log("      (* cxxrtl_edge = \"p\" *) input clk;\n");
3569			log("      input en;\n");
3570			log("      (* cxxrtl_width = \"WIDTH\" *) input [WIDTH - 1:0] i_data;\n");
3571			log("      (* cxxrtl_width = \"WIDTH\" *) output [WIDTH - 1:0] o_data;\n");
3572			log("    endmodule\n");
3573			log("\n");
3574			log("For this parametric HDL interface, this backend will generate the following C++\n");
3575			log("interface (only the differences are shown):\n");
3576			log("\n");
3577			log("    template<size_t WIDTH>\n");
3578			log("    struct bb_p_debug : public module {\n");
3579			log("      // ...\n");
3580			log("      value<WIDTH> p_i_data;\n");
3581			log("      wire<WIDTH> p_o_data;\n");
3582			log("      // ...\n");
3583			log("      static std::unique_ptr<bb_p_debug<WIDTH>>\n");
3584			log("      create(std::string name, metadata_map parameters, metadata_map attributes);\n");
3585			log("    };\n");
3586			log("\n");
3587			log("The `create' function must be implemented by the driver, specialized for every\n");
3588			log("possible combination of template parameters. (Specialization is necessary to\n");
3589			log("enable separate compilation of generated code and black box implementations.)\n");
3590			log("\n");
3591			log("    template<size_t SIZE>\n");
3592			log("    struct stderr_debug : public bb_p_debug<SIZE> {\n");
3593			log("      // ...\n");
3594			log("    };\n");
3595			log("\n");
3596			log("    template<>\n");
3597			log("    std::unique_ptr<bb_p_debug<8>>\n");
3598			log("    bb_p_debug<8>::create(std::string name, cxxrtl::metadata_map parameters,\n");
3599			log("                          cxxrtl::metadata_map attributes) {\n");
3600			log("      return std::make_unique<stderr_debug<8>>();\n");
3601			log("    }\n");
3602			log("\n");
3603			log("The following attributes are recognized by this backend:\n");
3604			log("\n");
3605			log("    cxxrtl_blackbox\n");
3606			log("        only valid on modules. if specified, the module contents are ignored,\n");
3607			log("        and the generated code includes only the module interface and a factory\n");
3608			log("        function, which will be called to instantiate the module.\n");
3609			log("\n");
3610			log("    cxxrtl_edge\n");
3611			log("        only valid on inputs of black boxes. must be one of \"p\", \"n\", \"a\".\n");
3612			log("        if specified on signal `clk`, the generated code includes edge detectors\n");
3613			log("        `posedge_p_clk()` (if \"p\"), `negedge_p_clk()` (if \"n\"), or both (if\n");
3614			log("        \"a\"), simplifying implementation of clocked black boxes.\n");
3615			log("\n");
3616			log("    cxxrtl_template\n");
3617			log("        only valid on black boxes. must contain a space separated sequence of\n");
3618			log("        identifiers that have a corresponding black box parameters. for each\n");
3619			log("        of them, the generated code includes a `size_t` template parameter.\n");
3620			log("\n");
3621			log("    cxxrtl_width\n");
3622			log("        only valid on ports of black boxes. must be a constant expression, which\n");
3623			log("        is directly inserted into generated code.\n");
3624			log("\n");
3625			log("    cxxrtl_comb, cxxrtl_sync\n");
3626			log("        only valid on outputs of black boxes. if specified, indicates that every\n");
3627			log("        bit of the output port is driven, correspondingly, by combinatorial or\n");
3628			log("        synchronous logic. this knowledge is used for scheduling optimizations.\n");
3629			log("        if neither is specified, the output will be pessimistically treated as\n");
3630			log("        driven by both combinatorial and synchronous logic.\n");
3631			log("\n");
3632			log("The following options are supported by this backend:\n");
3633			log("\n");
3634			log("    -print-wire-types, -print-debug-wire-types\n");
3635			log("        enable additional debug logging, for pass developers.\n");
3636			log("\n");
3637			log("    -header\n");
3638			log("        generate separate interface (.h) and implementation (.cc) files.\n");
3639			log("        if specified, the backend must be called with a filename, and filename\n");
3640			log("        of the interface is derived from filename of the implementation.\n");
3641			log("        otherwise, interface and implementation are generated together.\n");
3642			log("\n");
3643			log("    -namespace <ns-name>\n");
3644			log("        place the generated code into namespace <ns-name>. if not specified,\n");
3645			log("        \"cxxrtl_design\" is used.\n");
3646			log("\n");
3647			log("    -print-output <stream>\n");
3648			log("        $print cells in the generated code direct their output to <stream>.\n");
3649			log("        must be one of \"std::cout\", \"std::cerr\". if not specified,\n");
3650			log("        \"std::cout\" is used. explicitly provided performer overrides this.\n");
3651			log("\n");
3652			log("    -nohierarchy\n");
3653			log("        use design hierarchy as-is. in most designs, a top module should be\n");
3654			log("        present as it is exposed through the C API and has unbuffered outputs\n");
3655			log("        for improved performance; it will be determined automatically if absent.\n");
3656			log("\n");
3657			log("    -noflatten\n");
3658			log("        don't flatten the design. fully flattened designs can evaluate within\n");
3659			log("        one delta cycle if they have no combinatorial feedback.\n");
3660			log("        note that the debug interface and waveform dumps use full hierarchical\n");
3661			log("        names for all wires even in flattened designs.\n");
3662			log("\n");
3663			log("    -noproc\n");
3664			log("        don't convert processes to netlists. in most designs, converting\n");
3665			log("        processes significantly improves evaluation performance at the cost of\n");
3666			log("        slight increase in compilation time.\n");
3667			log("\n");
3668			log("    -O <level>\n");
3669			log("        set the optimization level. the default is -O%d. higher optimization\n", DEFAULT_OPT_LEVEL);
3670			log("        levels dramatically decrease compile and run time, and highest level\n");
3671			log("        possible for a design should be used.\n");
3672			log("\n");
3673			log("    -O0\n");
3674			log("        no optimization.\n");
3675			log("\n");
3676			log("    -O1\n");
3677			log("        unbuffer internal wires if possible.\n");
3678			log("\n");
3679			log("    -O2\n");
3680			log("        like -O1, and localize internal wires if possible.\n");
3681			log("\n");
3682			log("    -O3\n");
3683			log("        like -O2, and inline internal wires if possible.\n");
3684			log("\n");
3685			log("    -O4\n");
3686			log("        like -O3, and unbuffer public wires not marked (*keep*) if possible.\n");
3687			log("\n");
3688			log("    -O5\n");
3689			log("        like -O4, and localize public wires not marked (*keep*) if possible.\n");
3690			log("\n");
3691			log("    -O6\n");
3692			log("        like -O5, and inline public wires not marked (*keep*) if possible.\n");
3693			log("\n");
3694			log("    -g <level>\n");
3695			log("        set the debug level. the default is -g%d. higher debug levels provide\n", DEFAULT_DEBUG_LEVEL);
3696			log("        more visibility and generate more code, but do not pessimize evaluation.\n");
3697			log("\n");
3698			log("    -g0\n");
3699			log("        no debug information. the C API is disabled.\n");
3700			log("\n");
3701			log("    -g1\n");
3702			log("        include bare minimum of debug information necessary to access all design\n");
3703			log("        state. the C API is enabled.\n");
3704			log("\n");
3705			log("    -g2\n");
3706			log("        like -g1, but include debug information for all public wires that are\n");
3707			log("        directly accessible through the C++ interface.\n");
3708			log("\n");
3709			log("    -g3\n");
3710			log("        like -g2, and include debug information for public wires that are tied\n");
3711			log("        to a constant or another public wire.\n");
